"use client";

import { useEffect, useMemo, useState } from "react";
import Link from "next/link";

const API_BASE =
  process.env.NEXT_PUBLIC_API_BASE_URL || "http://localhost:4001";

type QRightObject = {
  id: string;
  title: string;
  description: string;
  kind: string;
  contentHash: string;
  ownerName: string | null;
  ownerEmail: string | null;
  signature: string | null;
  createdAt: string;
};

type VerifyResp = {
  valid?: boolean;
  expected?: string;
  provided?: string;
};

function shortHash(hash: string) {
  if (!hash) return "";
  if (hash.length <= 16) return hash;
  return `${hash.slice(0, 10)}…${hash.slice(-6)}`;
}

export default function AevionIpBureauPage() {
  const [items, setItems] = useState<QRightObject[]>([]);
  const [loading, setLoading] = useState(true);
  const [err, setErr] = useState<string | null>(null);

  const [verifyingId, setVerifyingId] = useState<string | null>(null);
  const [validMap, setValidMap] = useState<Record<string, boolean>>({});

  const load = async () => {
    try {
      setLoading(true);
      setErr(null);
      let headers: Record<string, string> | undefined = undefined;
      try {
        const t = localStorage.getItem("aevion_token") || "";
        if (t) headers = { Authorization: `Bearer ${t}` };
      } catch {
        // ignore
      }

      const res = await fetch(`${API_BASE}/api/qright/objects/signed`, {
        headers,
      });
      const data = await res.json().catch(() => null);
      if (!res.ok) {
        throw new Error(data?.error || "Ошибка загрузки подписанных объектов");
      }
      setItems((data?.items || []) as QRightObject[]);
    } catch (e: any) {
      setErr(e?.message || "Ошибка загрузки");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const signedCount = useMemo(() => items.length, [items]);

  const verifyOne = async (it: QRightObject) => {
    if (!it.signature) return;
    setVerifyingId(it.id);
    try {
      const res = await fetch(`${API_BASE}/api/qsign/verify`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          payload: { contentHash: it.contentHash },
          signature: it.signature,
        }),
      });
      const data = (await res.json().catch(() => null)) as VerifyResp | null;
      if (!res.ok) {
        throw new Error(
          data?.valid === false ? "Невалидна" : "Ошибка verify"
        );
      }
      const valid = Boolean(data?.valid);
      setValidMap((prev) => ({ ...prev, [it.id]: valid }));
    } catch (e: any) {
      setValidMap((prev) => ({ ...prev, [it.id]: false }));
      setErr(e?.message || "Ошибка проверки");
    } finally {
      setVerifyingId(null);
    }
  };

  return (
    <main style={{ padding: 24, maxWidth: 980 }}>
      <div style={{ display: "flex", justifyContent: "space-between", gap: 12 }}>
        <div>
          <h1 style={{ fontSize: 26, marginBottom: 6 }}>AEVION IP Bureau</h1>
          <p style={{ color: "#666", marginTop: 0 }}>
            Сертификаты на базе подписанного QRight (невозможно подделать подпись без серверного секрета).
          </p>
        </div>
        <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
          <Link href="/" style={{ color: "#0a5" }}>
            Globus
          </Link>
          <Link href="/qright" style={{ color: "#0a5" }}>
            QRight
          </Link>
          <Link href="/qsign" style={{ color: "#0a5" }}>
            QSign
          </Link>
        </div>
      </div>

      {err ? (
        <div style={{ margin: "12px 0", color: "crimson" }}>Ошибка: {err}</div>
      ) : null}

      <section
        style={{
          border: "1px solid #ddd",
          borderRadius: 12,
          padding: 14,
          marginTop: 18,
        }}
      >
        <h2 style={{ fontSize: 18, marginBottom: 10 }}>
          Подписанные объекты ({signedCount})
        </h2>

        {loading ? (
          <div>Загрузка…</div>
        ) : items.length === 0 ? (
          <div style={{ color: "#666" }}>Пока нет сертификатов.</div>
        ) : (
          <div style={{ display: "grid", gap: 12 }}>
            {items.slice(0, 20).map((it) => (
              <div
                key={it.id}
                style={{
                  border: "1px solid #eee",
                  borderRadius: 12,
                  padding: 14,
                  background: "#fff",
                }}
              >
                <div style={{ display: "flex", justifyContent: "space-between", gap: 12 }}>
                  <div style={{ fontWeight: 800, fontSize: 16 }}>{it.title}</div>
                  <div style={{ color: "#666", fontSize: 12 }}>
                    {new Date(it.createdAt).toLocaleString()}
                  </div>
                </div>

                <div style={{ marginTop: 6, color: "#666", fontSize: 13 }}>
                  owner:{" "}
                  <b>{it.ownerName ? it.ownerName : it.ownerEmail ? it.ownerEmail : "—"}</b>
                </div>

                <div style={{ marginTop: 10, fontFamily: "monospace", fontSize: 12, color: "#666" }}>
                  contentHash: {shortHash(it.contentHash)}
                </div>

                <div style={{ marginTop: 6, fontFamily: "monospace", fontSize: 12, color: "#666" }}>
                  signature: {it.signature ? shortHash(it.signature) : "—"}
                </div>

                <div style={{ marginTop: 10, display: "flex", gap: 10, flexWrap: "wrap" }}>
                  <button
                    type="button"
                    disabled={verifyingId === it.id}
                    onClick={() => verifyOne(it)}
                    style={{
                      padding: "8px 12px",
                      borderRadius: 8,
                      border: "1px solid #0a5",
                      background: "#0a5",
                      color: "#fff",
                      cursor: verifyingId === it.id ? "not-allowed" : "pointer",
                    }}
                  >
                    {verifyingId === it.id ? "Проверяем..." : "Проверить подпись"}
                  </button>

                  <button
                    type="button"
                    disabled
                    style={{
                      padding: "8px 12px",
                      borderRadius: 8,
                      border: "1px solid #ccc",
                      background: "#f5f5f5",
                      color: "#888",
                      cursor: "not-allowed",
                    }}
                  >
                    PDF сертификат (плейсхолдер)
                  </button>

                  {typeof validMap[it.id] === "boolean" ? (
                    <div style={{ color: validMap[it.id] ? "#0a5" : "crimson", fontWeight: 800 }}>
                      {validMap[it.id] ? "валидна" : "невалидна"}
                    </div>
                  ) : null}
                </div>
              </div>
            ))}
          </div>
        )}

        <div style={{ marginTop: 12, color: "#666", fontSize: 13 }}>
          Подпись выставляется только сервером и не перезаписывается.
        </div>
      </section>
    </main>
  );
}

